import{_ as i,c as e,o as s,ah as h}from"./chunks/framework.Cnj7lwEt.js";const c=JSON.parse('{"title":"GitHub 사용 가이드","description":"","frontmatter":{},"headers":[],"relativePath":"ko/github-guide.md","filePath":"ko/github-guide.md"}'),l={name:"ko/github-guide.md"};function t(r,a,n,d,o,k){return s(),e("div",null,a[0]||(a[0]=[h(`<h1 id="github-사용-가이드" tabindex="-1">GitHub 사용 가이드 <a class="header-anchor" href="#github-사용-가이드" aria-label="Permalink to “GitHub 사용 가이드”">​</a></h1><h2 id="_01-1-소개" tabindex="-1">01.1- 소개 <a class="header-anchor" href="#_01-1-소개" aria-label="Permalink to “01.1- 소개”">​</a></h2><p>GitHub은 세계 최대의 코드 호스팅 플랫폼으로, 개발자에게 강력한 버전 관리, 협업 개발, 프로젝트 관리 기능을 제공합니다.</p><h2 id="_01-2-기본-개념" tabindex="-1">01.2- 기본 개념 <a class="header-anchor" href="#_01-2-기본-개념" aria-label="Permalink to “01.2- 기본 개념”">​</a></h2><h3 id="_01-21-저장소" tabindex="-1">01.21- 저장소 <a class="header-anchor" href="#_01-21-저장소" aria-label="Permalink to “01.21- 저장소”">​</a></h3><p>저장소는 프로젝트의 저장 공간으로, 모든 파일, 폴더 및 각 파일의 수정 이력을 포함합니다.</p><h3 id="_01-22-브랜치" tabindex="-1">01.22- 브랜치 <a class="header-anchor" href="#_01-22-브랜치" aria-label="Permalink to “01.22- 브랜치”">​</a></h3><p>브랜치를 사용하면 메인 브랜치에 영향을 주지 않고, 새 기능 개발이나 문제 수정이 가능합니다.</p><h3 id="_01-23-커밋" tabindex="-1">01.23- 커밋 <a class="header-anchor" href="#_01-23-커밋" aria-label="Permalink to “01.23- 커밋”">​</a></h3><p>커밋은 파일에 대한 변경의 기록으로, 각 커밋에는 고유한 ID가 생성됩니다.</p><h3 id="_01-24-풀-리퀘스트" tabindex="-1">01.24- 풀 리퀘스트 <a class="header-anchor" href="#_01-24-풀-리퀘스트" aria-label="Permalink to “01.24- 풀 리퀘스트”">​</a></h3><p>풀 리퀘스트는 변경사항을 메인 브랜치에 병합하는 요청으로, 코드 리뷰와 토론을 용이하게 합니다.</p><h2 id="_01-3-퀵스타트" tabindex="-1">01.3- 퀵스타트 <a class="header-anchor" href="#_01-3-퀵스타트" aria-label="Permalink to “01.3- 퀵스타트”">​</a></h2><h3 id="_01-31-계정-생성" tabindex="-1">01.31- 계정 생성 <a class="header-anchor" href="#_01-31-계정-생성" aria-label="Permalink to “01.31- 계정 생성”">​</a></h3><p><a href="https://github.com" target="_blank" rel="noreferrer">GitHub 공식 사이트</a>에 접속하여 계정을 등록하세요.</p><h3 id="_01-32-저장소-생성" tabindex="-1">01.32- 저장소 생성 <a class="header-anchor" href="#_01-32-저장소-생성" aria-label="Permalink to “01.32- 저장소 생성”">​</a></h3><ol><li>우측 상단의 &quot;+&quot; 버튼 클릭</li><li>&quot;New repository&quot; 선택</li><li>저장소 이름과 설명 입력</li><li>공개 또는 비공개 선택</li><li>&quot;Create repository&quot; 클릭</li></ol><h3 id="_01-33-저장소-클론" tabindex="-1">01.33- 저장소 클론 <a class="header-anchor" href="#_01-33-저장소-클론" aria-label="Permalink to “01.33- 저장소 클론”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-브랜치-생성" tabindex="-1">01.34- 브랜치 생성 <a class="header-anchor" href="#_01-34-브랜치-생성" aria-label="Permalink to “01.34- 브랜치 생성”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-변경사항-커밋" tabindex="-1">01.35- 변경사항 커밋 <a class="header-anchor" href="#_01-35-변경사항-커밋" aria-label="Permalink to “01.35- 변경사항 커밋”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;새 기능 추가&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-풀-리퀘스트-생성" tabindex="-1">01.36- 풀 리퀘스트 생성 <a class="header-anchor" href="#_01-36-풀-리퀘스트-생성" aria-label="Permalink to “01.36- 풀 리퀘스트 생성”">​</a></h3><p>GitHub 웹페이지에서 풀 리퀘스트를 생성하고, 리뷰와 병합을 기다립니다.</p><h2 id="_01-4-자주-사용하는-작업" tabindex="-1">01.4- 자주 사용하는 작업 <a class="header-anchor" href="#_01-4-자주-사용하는-작업" aria-label="Permalink to “01.4- 자주 사용하는 작업”">​</a></h2><h3 id="_01-41-포크" tabindex="-1">01.41- 포크 <a class="header-anchor" href="#_01-41-포크" aria-label="Permalink to “01.41- 포크”">​</a></h3><p>포크를 사용하면 다른 사람의 프로젝트를 자신의 계정에 복사하여 수정할 수 있습니다.</p><h3 id="_01-42-스타" tabindex="-1">01.42- 스타 <a class="header-anchor" href="#_01-42-스타" aria-label="Permalink to “01.42- 스타”">​</a></h3><p>스타는 프로젝트가 마음에 든다는 것을 표시하며, 나중에 쉽게 찾을 수 있습니다.</p><h3 id="_01-43-워치" tabindex="-1">01.43- 워치 <a class="header-anchor" href="#_01-43-워치" aria-label="Permalink to “01.43- 워치”">​</a></h3><p>워치를 사용하면 프로젝트의 업데이트 알림을 받을 수 있습니다.</p><h3 id="_01-44-이슈" tabindex="-1">01.44- 이슈 <a class="header-anchor" href="#_01-44-이슈" aria-label="Permalink to “01.44- 이슈”">​</a></h3><p>이슈는 문제 보고, 기능 요청 또는 아이디어 토론에 사용됩니다.</p><h2 id="_01-5-모범-사례" tabindex="-1">01.5- 모범 사례 <a class="header-anchor" href="#_01-5-모범-사례" aria-label="Permalink to “01.5- 모범 사례”">​</a></h2><ol><li><strong>명확한 커밋 메시지</strong> - 각 커밋의 목적을 다른 사람에게 전달</li><li><strong>브랜치 사용</strong> - 메인 브랜치에서 직접 개발하지 않기</li><li><strong>정기적 동기화</strong> - 로컬 저장소를 원격 저장소와 동기화</li><li><strong>코드 리뷰</strong> - 풀 리퀘스트를 통해 코드 리뷰 실시</li><li><strong>문서화</strong> - 프로젝트에 README와 필요한 문서 추가</li></ol><h2 id="_01-6-관련-리소스" tabindex="-1">01.6- 관련 리소스 <a class="header-anchor" href="#_01-6-관련-리소스" aria-label="Permalink to “01.6- 관련 리소스”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">GitHub 공식 문서</a></li><li><a href="/ko/91git.html">Git 기본 튜토리얼</a></li><li><a href="/ko/全部资源概述.html">전체 리소스 개요</a></li></ul>`,38)]))}const b=i(l,[["render",t]]);export{c as __pageData,b as default};
